import './Tab.scss';

import { getBEMClasses } from ':helpers/get-bem';
import React, { useEffect, useImperativeHandle, useMemo, useRef } from 'react';

import { classNames } from '../../../helpers/classnames';
import { Icon } from '../../Icon';
import type { InnerTabProps, TabProps } from './Tab.types';

const [tabClassName, tabModifier, tabElement] = getBEMClasses('dsb_tab-new');
const [tabContentClassName] = tabElement('content');
const [tabIndicatorClassName] = tabElement('indicator');
const [tabLabelClassName] = tabElement('label');
const [tabIconClassName] = tabElement('icon');

export const Tab = React.forwardRef<HTMLButtonElement, TabProps>((props, ref) => {
	const {
		className,
		value,
		label,
		onClick,
		iconName,
		children,
		selected,
		onSelected,
		disabled,
		routingComponent,
		...rest
	} = props as InnerTabProps;

	const contentRef = useRef<HTMLDivElement>(null);

	const localRef = useRef<HTMLButtonElement>(null) as React.MutableRefObject<HTMLButtonElement>;
	useImperativeHandle(ref, () => localRef.current);
	// вызываем колбек если таб выбран
	useEffect(() => {
		if (selected) {
			onSelected({
				tabBody: children,
				tabElement: contentRef.current,
			});
		}
	}, [selected, onSelected, children, label]);

	const buttonClassName = useMemo<string>(
		() =>
			classNames(
				tabClassName,
				{
					[tabModifier('icon-only')]: iconName && !label,
					[tabModifier('selected')]: selected,
				},
				className,
			),
		[iconName, label, selected, className],
	);

	const handlerClick = (): void => {
		// TODO: подумать всегда ли надо подкручивать скролл или необходимо предоставить выбор пользователю
		// при клике на таб скроллим вью пользователя к контенту
		// localRef?.current?.scrollIntoView();

		onClick?.(value);
	};

	const content = (
		<div className={tabContentClassName} ref={contentRef}>
			{iconName && <Icon iconName={iconName} className={tabIconClassName} />}
			{label && <span className={tabLabelClassName}>{label}</span>}
			<div className={tabIndicatorClassName} />
		</div>
	);

	return (
		<>
			{routingComponent ? (
				React.cloneElement<any>(
					routingComponent,
					{
						className: buttonClassName,
						disabled: disabled,
						onClick: handlerClick,
						ref: localRef,
						'data-testid': 'tab',
						...rest,
					},
					content,
				)
			) : (
				<button
					data-testid="Tab"
					ref={localRef}
					className={buttonClassName}
					disabled={disabled}
					onClick={handlerClick}
					{...rest}
				>
					{content}
				</button>
			)}
		</>
	);
});
